const text =
  $json.chatInput ||
  $json.message ||
  $json.text ||
  '';

if (!text || !String(text).trim()) {
  return {
    valid: false,
    error_stage: 'input_validation',
    error_message: 'Empty message received. Use format: C001: Your question',
    raw_message: text || ''
  };
}

if (!String(text).includes(':')) {
  return {
    valid: false,
    error_stage: 'input_validation',
    error_message: 'Invalid format. Use: C001: Your question',
    raw_message: text
  };
}

const parts = String(text).split(':');
const client_id = (parts[0] || '').trim().toUpperCase();
const question = parts.slice(1).join(':').trim();

if (!client_id) {
  return {
    valid: false,
    error_stage: 'input_validation',
    error_message: 'Client ID is missing. Use format: C001: Your question',
    raw_message: text
  };
}

if (!question) {
  return {
    valid: false,
    error_stage: 'input_validation',
    error_message: 'Question is missing after client ID.',
    raw_message: text,
    client_id
  };
}

return {
  valid: true,
  raw_message: text,
  client_id,
  question,
  source_channel: 'chat',
  received_at: new Date().toISOString()
};

return [{
  json: {
    status: 'failed',
    error_stage: $json.error_stage || 'input_validation',
    action_taken: 'Rejected invalid input',
    client_id: $json.client_id || null,
    question: $json.question || null,
    raw_message: $json.raw_message || null,
    reply: $json.error_message || 'Invalid input',
    source_channel: $json.source_channel || 'chat',
    timestamp: new Date().toISOString()
  }
}];

const parsed = $('Parse Client Message').first().json;

return [{
  json: {
    status: 'failed',
    error_stage: 'client_lookup',
    action_taken: 'Stopped because client was not found',
    client_id: parsed.client_id || null,
    question: parsed.question || null,
    reply: `Client ID ${parsed.client_id || ''} was not found in the client sheet.`,
    source_channel: parsed.source_channel || 'chat',
    timestamp: new Date().toISOString()
  }
}];

const holdings = $input.all().map(item => item.json).filter(x => Object.keys(x).length > 0);
const parsed = $('Parse Client Message').first().json;
const client = $('Get Client Profile').first().json || {};

if (!holdings.length) {
  return [{
    json: {
      holdings_found: false,
      client_id: parsed.client_id,
      question: parsed.question,
      client_name: client.client_name || null
    }
  }];
}

const symbols = holdings
  .map(h => (h.symbol || '').trim().toUpperCase())
  .filter(Boolean);

return [{
  json: {
    holdings_found: true,
    holdings,
    symbols,
    client_id: parsed.client_id,
    question: parsed.question,
    client_name: client.client_name || null,
    risk_profile: client.risk_profile || null,
    goal: client.goal || null,
    tone: client.tone || 'simple',
    source_channel: parsed.source_channel || 'chat',
    received_at: parsed.received_at
  }
}];

const item = $input.first().json;

return [{
  json: {
    status: 'failed',
    error_stage: 'holdings_lookup',
    action_taken: 'Stopped because no holdings were found',
    client_id: item.client_id || null,
    question: item.question || null,
    reply: `No holdings were found for client ${item.client_id || ''}.`,
    source_channel: item.source_channel || 'chat',
    timestamp: new Date().toISOString()
  }
}];

const prep = $('Prepare Symbols').first().json;
const api = $input.first().json || {};

const prices = api.prices || {};
const errors = api.errors || {};
const apiWorked = !!api.prices || Object.keys(api).length > 0;

return [{
  json: {
    ...prep,
    api_worked: apiWorked,
    prices,
    price_errors: errors,
    raw_price_response: api
  }
}];

const item = $input.first().json;

return [{
  json: {
    status: 'failed',
    error_stage: 'market_api',
    action_taken: 'Stopped because live price API failed',
    client_id: item.client_id || null,
    question: item.question || null,
    reply: 'Live market prices could not be fetched right now. Please try again shortly.',
    source_channel: item.source_channel || 'chat',
    timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;
const holdings = data.holdings || [];
const prices = data.prices || {};
const errors = data.price_errors || {};

const merged = holdings.map(h => {
  const symbol = (h.symbol || '').trim().toUpperCase();
  const p = prices[symbol] || {};
  const quantity = Number(h.quantity || 0);
  const avgBuy = Number(h.avg_buy_price || 0);
  const invested = quantity * avgBuy;

  const hasPrice =
    p.last_price !== undefined &&
    p.last_price !== null &&
    p.last_price !== '';

  const ltp = hasPrice ? Number(p.last_price) : null;
  const current_value = hasPrice ? quantity * ltp : null;
  const pnl = hasPrice ? current_value - invested : null;
  const pnl_pct = hasPrice && invested ? (pnl / invested) * 100 : null;

  return {
    row_number: h.row_number ?? null,
    client_id: h.client_id,
    asset_name: h.asset_name,
    symbol,
    asset_type: h.asset_type,
    quantity,
    avg_buy_price: avgBuy,
    ltp,
    invested,
    current_value,
    pnl,
    pnl_pct,
    price_available: hasPrice,
    price_error: errors[symbol] || null
  };
});

const validHoldings = merged.filter(h =>
  h.price_available &&
  h.current_value !== null &&
  h.pnl !== null &&
  h.pnl_pct !== null
);

const total_invested_all = merged.reduce((sum, h) => sum + Number(h.invested || 0), 0);
const total_invested_priced = validHoldings.reduce((sum, h) => sum + Number(h.invested || 0), 0);
const total_current_value = validHoldings.reduce((sum, h) => sum + Number(h.current_value || 0), 0);
const total_pnl = total_current_value - total_invested_priced;
const total_return_pct = total_invested_priced ? (total_pnl / total_invested_priced) * 100 : 0;

const sortedAsc = [...validHoldings].sort((a, b) => a.pnl_pct - b.pnl_pct);
const sortedDesc = [...validHoldings].sort((a, b) => b.pnl_pct - a.pnl_pct);

const weakest_performer = sortedAsc[0] || null;
const best_performer = sortedDesc[0] || null;

const missing_prices = merged
  .filter(h => !h.price_available)
  .map(h => ({
    symbol: h.symbol,
    asset_name: h.asset_name,
    invested: h.invested,
    reason: h.price_error || 'Price not available'
  }));

return [{
  json: {
    client_id: data.client_id,
    client_name: data.client_name,
    question: data.question,
    risk_profile: data.risk_profile,
    goal: data.goal,
    tone: data.tone,
    source_channel: data.source_channel,
    received_at: data.received_at,
    holdings: merged,
    portfolio_summary: {
      total_invested_all,
      total_invested_priced,
      total_current_value,
      total_pnl,
      total_return_pct,
      priced_holdings_count: validHoldings.length,
      missing_price_count: missing_prices.length
    },
    best_performer,
    weakest_performer,
    missing_prices
  }
}];

const portfolio = $('Merge Portfolio Data').first().json;
const ctx = $input.first().json || {};

const market_context = {
  nifty_change_pct: ctx.nifty_change_pct ?? null,
  sensex_change_pct: ctx.sensex_change_pct ?? null,
  market_tone: ctx.market_tone ?? 'not available',
  summary: ctx.summary ?? 'Market context not available'
};

return [{
  json: {
    ...portfolio,
    market_context
  }
}];

const data = $input.first().json;

          const holdingsText = (data.holdings || [])
            .map(h => {
              const invested = h.invested != null ? `₹${Number(h.invested).toFixed(2)}` : 'N/A';
              const ltp = h.ltp != null ? `₹${Number(h.ltp).toFixed(2)}` : 'N/A';
              const currentValue = h.current_value != null ? `₹${Number(h.current_value).toFixed(2)}` : 'N/A';
              const pnl = h.pnl != null ? `₹${Number(h.pnl).toFixed(2)}` : 'N/A';
              const pnlPct = h.pnl_pct != null ? `${Number(h.pnl_pct).toFixed(2)}%` : 'N/A';

              return `- ${h.asset_name} (${h.symbol}): quantity ${h.quantity}, avg buy ₹${Number(h.avg_buy_price).toFixed(2)}, invested ${invested}, LTP ${ltp}, current value ${currentValue}, P&L ${pnl}, return ${pnlPct}, price available ${h.price_available ? 'yes' : 'no'}`;
            })
            .join('\n');

          const missingPricesText = (data.missing_prices || []).length
            ? data.missing_prices
                .map(x => `- ${x.asset_name} (${x.symbol}): invested ₹${Number(x.invested || 0).toFixed(2)}, reason: ${x.reason}`)
                .join('\n')
            : 'None';

          const prompt = `
You are a financial assistant.

STRICT RULES:
- Use ONLY the numbers and facts provided below.
- Never calculate new numbers on your own.
- Never invent market reasons, company news or assumptions.
- Never give buy/sell advice unless explicitly asked.
- Keep the reply short, clear and client-friendly.
- Maximum 4 short lines.
- Reply in this order:
  1. Overall portfolio summary
  2. Best and weakest performer
  3. Missing price note if applicable
  4. Direct answer to the question

Client profile:
Name: ${data.client_name || 'Client'}
Risk profile: ${data.risk_profile || 'N/A'}
Goal: ${data.goal || 'N/A'}
Tone: ${data.tone || 'simple'}

Client question:
${data.question}

Portfolio summary:
- Total invested across all holdings: ₹${Number(data.portfolio_summary.total_invested_all).toFixed(2)}
- Total invested in priced holdings: ₹${Number(data.portfolio_summary.total_invested_priced).toFixed(2)}
- Current value of priced holdings: ₹${Number(data.portfolio_summary.total_current_value).toFixed(2)}
- Overall P&L on priced holdings: ₹${Number(data.portfolio_summary.total_pnl).toFixed(2)}
- Return on priced holdings: ${Number(data.portfolio_summary.total_return_pct).toFixed(2)}%
- Best performer: ${data.best_performer?.asset_name || 'N/A'} (${data.best_performer?.symbol || 'N/A'}), P&L ${data.best_performer?.pnl != null ? `₹${Number(data.best_performer.pnl).toFixed(2)}` : 'N/A'}, return ${data.best_performer?.pnl_pct != null ? `${Number(data.best_performer.pnl_pct).toFixed(2)}%` : 'N/A'}
- Weakest performer: ${data.weakest_performer?.asset_name || 'N/A'} (${data.weakest_performer?.symbol || 'N/A'}), P&L ${data.weakest_performer?.pnl != null ? `₹${Number(data.weakest_performer.pnl).toFixed(2)}` : 'N/A'}, return ${data.weakest_performer?.pnl_pct != null ? `${Number(data.weakest_performer.pnl_pct).toFixed(2)}%` : 'N/A'}
- Priced holdings count: ${data.portfolio_summary.priced_holdings_count}
- Missing price count: ${data.portfolio_summary.missing_price_count}

Optional market context:
- Nifty change: ${data.market_context?.nifty_change_pct ?? 'N/A'}
- Sensex change: ${data.market_context?.sensex_change_pct ?? 'N/A'}
- Market tone: ${data.market_context?.market_tone ?? 'N/A'}
- Market summary: ${data.market_context?.summary ?? 'N/A'}

Holdings details:
${holdingsText}

Missing price holdings:
${missingPricesText}
          `.trim();

          return [{
            json: {
              client_id: data.client_id,
              client_name: data.client_name,
              question: data.question,
              source_channel: data.source_channel,
              received_at: data.received_at,
              prompt
            }
          }];

const parsed = $('Build AI Prompt').first().json;
const res = $input.first().json || {};

const reply =
  res.content?.parts?.[0]?.text ||
  res.candidates?.[0]?.content?.parts?.[0]?.text ||
  res.text ||
  null;

if (!reply) {
  return [{
    json: {
      success: false,
      client_id: parsed.client_id,
      question: parsed.question,
      source_channel: parsed.source_channel,
      received_at: parsed.received_at,
      reply: null
    }
  }];
}

return [{
  json: {
    success: true,
    client_id: parsed.client_id,
    question: parsed.question,
    source_channel: parsed.source_channel,
    received_at: parsed.received_at,
    reply: String(reply).trim()
  }
}];

const item = $input.first().json;

return [{
  json: {
    status: 'failed',
    error_stage: 'ai_generation',
    action_taken: 'Stopped because AI reply was empty',
    client_id: item.client_id || null,
    question: item.question || null,
    reply: 'AI could not generate a response right now. Please try again.',
    source_channel: item.source_channel || 'chat',
    timestamp: new Date().toISOString()
  }
}];

const item = $input.first().json;

return [{
  json: {
    status: 'success',
    error_stage: null,
    action_taken: 'Generated portfolio reply',
    client_id: item.client_id,
    question: item.question,
    reply: item.reply,
    source_channel: item.source_channel || 'chat',
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    final_status: $json.status,
    client_id: $json.client_id,
    question: $json.question,
    reply: $json.reply,
    action_taken: $json.action_taken
  }
}];
